import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





// Place helper components here if needed

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object

  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({ name: '', email: '', satisfaction: 0, features: [] as string[], comments: '' });
  const [errors, setErrors] = useState({ name: '', email: '' });

  const validate = () => {
    let valid = true;
    const newErrors = { name: '', email: '' };
    if (!formData.name) { newErrors.name = 'Required'; valid = false; }
    if (!formData.email || !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(formData.email)) {
      newErrors.email = 'Valid email required';
      valid = false;
    }
    setErrors(newErrors);
    return valid;
  };

  const nextStep = () => {
    if (step === 1 && !validate()) return;
    setStep(Math.min(step + 1, 5));
  };
  const prevStep = () => setStep(Math.max(step - 1, 1));

  const updateField = (field: keyof typeof formData, value: any) => setFormData(d => ({ ...d, [field]: value }));
  const toggleFeature = (feature: string) => {
    const features = formData.features.includes(feature) ? formData.features.filter(f => f !== feature) : [...formData.features, feature];
    updateField('features', features);
  };

  const isNextDisabled = step === 1 && (!formData.name || !formData.email);
  const progress = (Math.min(step, 4) / 4) * 100;

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-4)">
        <Heading level={2}>Survey</Heading>
        <Stack gap="var(--ggui-spacing-2)">
          <Text variant="label">Step {Math.min(step, 4)} of 4</Text>
          <Progress value={progress} />
        </Stack>

        <Card padding="var(--ggui-spacing-6)">
          {step === 1 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Input label="Name" value={formData.name} onChange={(v: string) => updateField('name', v)} error={errors.name} />
              <Input label="Email" type="email" value={formData.email} onChange={(v: string) => updateField('email', v)} error={errors.email} />
            </Stack>
          )}

          {step === 2 && (
            <RadioGroup label="Satisfaction Rating" value={formData.satisfaction.toString()} onChange={(v: string) => updateField('satisfaction', parseInt(v))} 
              options={props.satisfactionLabels.map((l, i) => ({ value: (i + 1).toString(), label: l }))} />
          )}

          {step === 3 && (
            <Stack gap="var(--ggui-spacing-2)">
              <Text variant="label">Feature Interests</Text>
              {props.featureOptions.map(f => (
                <Checkbox key={f} label={f} checked={formData.features.includes(f)} onChange={() => toggleFeature(f)} />
              ))}
            </Stack>
          )}

          {step === 4 && (
            <Stack gap="var(--ggui-spacing-1)">
              <TextArea 
                label="Comments" 
                value={formData.comments} 
                onChange={(v: string) => v.length <= 500 && updateField('comments', v)} 
              />
              <Text variant="caption">{formData.comments.length} / 500 characters</Text>
            </Stack>
          )}

          {step === 5 && (
            <Stack gap="var(--ggui-spacing-3)">
              <Heading level={4}>Review Your Answers</Heading>
              <Text>Name: {formData.name}</Text>
              <Text>Email: {formData.email}</Text>
              <Text>Satisfaction: {formData.satisfaction}</Text>
              <Text>Features: {formData.features.join(', ')}</Text>
              <Text>Comments: {formData.comments}</Text>
            </Stack>
          )}
        </Card>

        <Row gap="var(--ggui-spacing-3)">
          <Button as={Clickable} onClick={prevStep} disabled={step === 1 || step === 5}>Back</Button>
          {step < 4 ? (
            <Button as={Clickable} onClick={nextStep} disabled={isNextDisabled}>Next</Button>
          ) : step === 4 ? (
            <Button as={Clickable} onClick={nextStep}>Review</Button>
          ) : (
            <Button as={Clickable} onClick={() => submit(formData)}>Submit</Button>
          )}
        </Row>
      </Stack>
    </Container>
  );
}

