import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column: string } };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };




const TaskCard = ({ task, onUpdate, columns }: { task: any, onUpdate: any, columns: any[] }) => {
  const [editing, setEditing] = useState(false);
  const [data, setData] = useState({ title: task.title, priority: task.priority, dueDate: task.dueDate });
  const priorityColors = { low: 'var(--ggui-color-success-500)', medium: 'var(--ggui-color-warning-500)', high: 'var(--ggui-color-error-500)' };
  const handleSave = () => { onUpdate('edit', task.id, data); setEditing(false); };
  return (
    <Card padding="var(--ggui-spacing-3)">
      <Stack gap="var(--ggui-spacing-2)">
        {editing ? (
          <Stack gap="var(--ggui-spacing-2)">
            <Input label="Title" value={data.title} onChange={(v) => setData({...data, title: v})} />
            <Select label="Priority" value={data.priority} onChange={(v) => setData({...data, priority: v})} options={[{label:'Low', value:'low'}, {label:'Medium', value:'medium'}, {label:'High', value:'high'}]} />
            <Input label="Due Date" value={data.dueDate || ''} onChange={(v) => setData({...data, dueDate: v})} />

            <Button as={Clickable} onClick={handleSave}>Save Changes</Button>
          </Stack>
        ) : (
          <Box as={Clickable} onClick={() => setEditing(true)}>
            <Text>{task.title}</Text>
            <Row justify="between">
              <Badge style={{ color: priorityColors[task.priority as 'low' | 'medium' | 'high'] }}>{task.priority}</Badge>
              <Text variant="bodySmall">Due: {task.dueDate || 'N/A'}</Text>
            </Row>
          </Box>
        )}
        <Select label="Move to" value={task.column} onChange={(col) => onUpdate('move', task.id, { column: col })} options={columns.map(c => ({ value: c.id, label: c.name }))} />
      </Stack>
    </Card>
  );
};




export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate'); // Called when a task is moved, edited, or created. Payload: { action, taskId, data }

  // Streams — real-time from agent (.latest, .all)
  const taskChanged = useStream<StreamTaskChanged>('taskChanged'); // A task was moved, edited, or created by another user — update it in the board

  const [tasks, setTasks] = useState(props.tasks || []);
  const [isAdding, setIsAdding] = useState<string | null>(null);
  const [newTask, setNewTask] = useState({ title: '', priority: 'medium' as 'low' | 'medium' | 'high' });

  useEffect(() => {
    if (props.tasks) setTasks(props.tasks);
  }, [props.tasks]);

  useEffect(() => {
    if (taskChanged.latest) {
      const { action, task } = taskChanged.latest;
      if (task?.id && (action === 'create' || action === 'edit' || action === 'move')) {
        setTasks(prev => {
          const filtered = prev.filter(t => t.id !== task.id);
          return [...filtered, task];
        });
      }
    }
  }, [taskChanged.latest]);


  const handleUpdate = useCallback((action: string, taskId: string, data: any) => {
    taskUpdate({ action, taskId, data });
    setTasks(prev => prev.map(t => t.id === taskId ? { ...t, ...data } : t));
  }, [taskUpdate]);

  const addTask = useCallback((columnId: string) => {
    const id = Date.now().toString();
    const task = { id, title: newTask.title, priority: newTask.priority, column: columnId, assignee: 'ME' };
    taskUpdate({ action: 'create', taskId: id, data: task as any });
    setTasks(prev => [...prev, task]);
    setIsAdding(null);
    setNewTask({ title: '', priority: 'medium' });
  }, [newTask, taskUpdate]);

  const stats = useMemo(() => {
    const total = tasks.length;
    const done = tasks.filter(t => t.column === 'done').length;
    return { total, done };
  }, [tasks]);

  return (
    <Container maxWidth="xl" style={{ padding: 'var(--ggui-spacing-6)' }}>
      <Stack gap="var(--ggui-spacing-6)">
        <Row justify="between" align="center" style={{ padding: 'var(--ggui-spacing-4)', background: 'var(--ggui-color-surface-variant)', borderRadius: 'var(--ggui-shape-radius-lg)' }}>
          <Heading level={2}>Project Board</Heading>
          <Text>Total Tasks: {stats.total} | Completed: {stats.done}</Text>
        </Row>

        <Row gap="var(--ggui-spacing-4)" align="start">
          {props.columns.map(col => (
            <Stack key={col.id} gap="var(--ggui-spacing-4)" style={{ flex: 1 }}>
              <Row justify="between">
                <Heading level={4}>{col.name}</Heading>
                <Badge>{tasks.filter(t => t.column === col.id).length}</Badge>
              </Row>
              <Stack gap="var(--ggui-spacing-3)">
                {tasks.filter(t => t.column === col.id).map(t => (
                  <TaskCard key={t.id} task={t} onUpdate={handleUpdate} columns={props.columns} />
                ))}
                {isAdding === col.id ? (
                  <Card padding="var(--ggui-spacing-3)">
                    <Stack gap="var(--ggui-spacing-2)">
                      <Input label="Title" value={newTask.title} onChange={(v) => setNewTask({...newTask, title: v})} />
                      <Select label="Priority" value={newTask.priority} onChange={(v) => setNewTask({...newTask, priority: v as any})} options={[{label:'Low', value:'low'}, {label:'Medium', value:'medium'}, {label:'High', value:'high'}]} />
                      <Row gap="var(--ggui-spacing-2)">
                        <Button as={Clickable} onClick={() => addTask(col.id)}>Save</Button>
                        <Button as={Clickable} onClick={() => setIsAdding(null)}>Cancel</Button>
                      </Row>
                    </Stack>
                  </Card>
                ) : (
                  <Button as={Clickable} onClick={() => setIsAdding(col.id)}>+ Add Task</Button>
                )}
              </Stack>
            </Stack>
          ))}
        </Row>
      </Stack>
    </Container>
  );

}

