// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  elements: Array<{ atomicNumber?: number; symbol?: string; name?: string; atomicWeight?: number; category?: string; row?: number; col?: number }>; // Full periodic table element data
}





const CATEGORIES = {
  'alkali-metal': 'var(--ggui-color-error-500)',
  'alkaline-earth-metal': 'var(--ggui-color-warning-500)',
  'transition-metal': 'var(--ggui-color-primary-500)',
  'post-transition-metal': 'var(--ggui-color-primary-300)',
  'lanthanide': 'var(--ggui-color-success-300)',
  'actinide': 'var(--ggui-color-success-500)',
  'metalloid': 'var(--ggui-color-info-300)',
  'reactive-nonmetal': 'var(--ggui-color-info-500)',
  'noble-gas': 'var(--ggui-color-success-700)',
  'unknown': 'var(--ggui-color-outline)',
};

function getCategoryColor(category?: string) {
  return CATEGORIES[category as keyof typeof CATEGORIES] || CATEGORIES['unknown'];
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract

  const [search, setSearch] = useState('');
  const [selected, setSelected] = useState<typeof props.elements[0] | null>(null);


  const filteredElements = useMemo(() => {
    if (!search) return props.elements;
    const lower = search.toLowerCase();
    return props.elements.filter(
      (e) =>
        e.name?.toLowerCase().includes(lower) ||
        e.symbol?.toLowerCase().includes(lower)
    );
  }, [props.elements, search]);

  return (
    <Container maxWidth="3xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Heading level={1}>Periodic Table of Elements</Heading>

        <Input
          label="Search by Name or Symbol"
          value={search}
          onChange={(val: string) => setSearch(val)}
          placeholder="e.g. Hydrogen or H"
        />


        <Box
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(18, 1fr)',
            gap: 'var(--ggui-spacing-1)',
          }}
        >
          {(props.elements || []).map((el) => {
            const isVisible = filteredElements.includes(el);
            return (
              <Card
                as={Clickable}
                tabIndex={0}
                key={el.atomicNumber}
                onClick={() => setSelected(el)}
                onKeyDown={(e: any) => e.key === 'Enter' && setSelected(el)}
                style={{
                  gridRow: el.row,
                  gridColumn: el.col,
                  padding: 'var(--ggui-spacing-2)',
                  aspectRatio: '1',
                  display: 'flex',
                  flexDirection: 'column',
                  justifyContent: 'center',
                  alignItems: 'center',
                  background: getCategoryColor(el.category),
                  opacity: isVisible ? 1 : 0.2,
                  transition: 'transform 0.2s, opacity 0.2s',
                  cursor: 'pointer',
                }}
              >
                <Text variant="caption" style={{ alignSelf: 'flex-start' }}>{el.atomicNumber}</Text>
                <Heading level={6}>{el.symbol}</Heading>
              </Card>
            );
          })}
        </Box>


        <Card padding="var(--ggui-spacing-4)">
          <Stack direction="horizontal" gap="var(--ggui-spacing-4)" wrap>
            {Object.entries(CATEGORIES).map(([cat, color]) => (
              <Row key={cat} gap="var(--ggui-spacing-1)" align="center">
                <Box style={{ width: 12, height: 12, background: color }} borderRadius="var(--ggui-shape-radius-sm)" />
                <Text variant="caption">{cat.replace('-', ' ')}</Text>
              </Row>
            ))}
          </Stack>
        </Card>

        {selected && (
          <Card padding="var(--ggui-spacing-6)">
            <Stack gap="var(--ggui-spacing-3)">
              <Heading level={2}>{selected.name || 'Unknown'}</Heading>
